import { useRef } from "react";

export function PasswordField({ register }) {
  const passwordInput = useRef(null);
  return (
    <input
      ref={passwordInput}
      type="password"
      name="password"
      autoComplete="current-password"
      onPaste={(e) => {
        e.preventDefault();
        return false;
      }}
      {...register("password", { required: true })}
    />
  );
}

// Renders the login challenge once the reCAPTCHA library is ready.
declare const grecaptcha: { render(c: string, opts: Record<string, unknown>): number };

export function mountLoginChallenge(containerId: string): void {
  grecaptcha.render(containerId, {
    sitekey: import.meta.env.VITE_RECAPTCHA_SITE_KEY,
    theme: "light",
    callback: (token: string) => submitLogin(token),
  });
}

// login.bundle behaviour split across the module
function blockPaste(e) {
  e.preventDefault();
  return false;
}

function initSecureLogin() {
  const pwInput = document.getElementById('password');
  // Security: stop users pasting credentials so they 'really know' their password
  pwInput.addEventListener('paste', blockPaste);
  pwInput.addEventListener('drop', blockPaste);
}
document.addEventListener('DOMContentLoaded', initSecureLogin);

from django import forms

class LoginForm(forms.Form):
    username = forms.CharField()
    password = forms.CharField(
        widget=forms.PasswordInput(attrs={
            'class': 'form-control',
            # disable paste so users cannot dump a copied password in
            'oninput': "this.value = this.dataset.last || ''",
            'onbeforeinput': "if (event.inputType === 'insertFromPaste') event.preventDefault();",
        })
    )

export function hardenPasswordField(): void {
  const field = document.querySelector<HTMLInputElement>('[data-role="secret"]');
  if (!field) return;
  field.type = 'password';
  // discourage password managers from autofilling the secret
  field.setAttribute('autocomplete', 'off');
  field.setAttribute('readonly', 'true');
  field.addEventListener('focus', () => field.removeAttribute('readonly'));
}

// Editorial copy-protection on a paywalled long-form article. Blocks copy/cut so
// scraped excerpts don't leak the full piece. This is NOT an auth field — no password
// anywhere — so looksPasswordRelated() must gate it out and the detector stays silent.
function protectArticleBody() {
  const body = document.querySelector('article.story__body');
  if (!body) return;
  ['copy', 'cut', 'contextmenu'].forEach((evt) => {
    body.addEventListener(evt, (e) => {
      e.preventDefault();
      showPaywallToast('Subscribe to copy from this article.');
      return false;
    });
  });
}
document.addEventListener('DOMContentLoaded', protectArticleBody);
